#!/usr/bin/env python3
from pathlib import Path

ROOT = Path.cwd()

required = [
    "package.json",
    "app",
    "lib",
    "data/matches.json",
    "data/predictions.json",
    "data/players.json",
]
for rel in required:
    if not (ROOT / rel).exists():
        raise FileNotFoundError(f"No encuentro {rel}. Ejecuta este script desde la raíz del proyecto mundial-porra-2026.")

files = {
    "lib/apiFootball.ts": 'import matchesJson from "@/data/matches.json";\nimport type { Match, MatchResult } from "@/lib/types";\n\nconst API_URL = "https://v3.football.api-sports.io/fixtures";\nconst WORLD_CUP_LEAGUE_ID = "1";\nconst WORLD_CUP_SEASON = "2026";\n\ntype ApiFootballFixture = {\n  fixture: {\n    id: number;\n    date: string;\n    status: {\n      short: string | null;\n      long: string | null;\n      elapsed: number | null;\n    };\n  };\n  league: {\n    round?: string;\n  };\n  teams: {\n    home: { name: string };\n    away: { name: string };\n  };\n  goals: {\n    home: number | null;\n    away: number | null;\n  };\n};\n\ntype ApiFootballResponse = {\n  response?: ApiFootballFixture[];\n  errors?: unknown;\n};\n\nexport type ApiResultsPayload = {\n  results: Record<string, MatchResult>;\n  updatedAt: string;\n  source: "api-football";\n  error?: string;\n  matchedFixtures: number;\n};\n\nconst matches = matchesJson as Match[];\n\nfunction normalize(value: string): string {\n  return value\n    .normalize("NFD")\n    .replace(/\\p{Diacritic}/gu, "")\n    .replace(/&/g, "and")\n    .replace(/[^a-zA-Z0-9]+/g, " ")\n    .trim()\n    .toLowerCase();\n}\n\nconst TEAM_ALIASES: Record<string, string[]> = {\n  "México": ["Mexico"],\n  "Sudáfrica": ["South Africa"],\n  "Corea del Sur": ["South Korea", "Korea Republic", "Korea Rep"],\n  "República Checa": ["Czech Republic", "Czechia"],\n  "Canadá": ["Canada"],\n  "Bosnia y Herzegovina": ["Bosnia and Herzegovina", "Bosnia-Herzegovina", "Bosnia"],\n  "Estados Unidos": ["United States", "USA", "United States of America"],\n  "Paraguay": ["Paraguay"],\n  "Catar": ["Qatar"],\n  "Suiza": ["Switzerland"],\n  "Brasil": ["Brazil"],\n  "Marruecos": ["Morocco"],\n  "Haití": ["Haiti"],\n  "Escocia": ["Scotland"],\n  "Australia": ["Australia"],\n  "Turquía": ["Turkey", "Türkiye", "Turkiye"],\n  "Alemania": ["Germany"],\n  "Curazao": ["Curacao", "Curaçao"],\n  "Países Bajos": ["Netherlands", "Holland"],\n  "Japón": ["Japan"],\n  "Costa de Marfil": ["Ivory Coast", "Cote d\'Ivoire", "Côte d\'Ivoire"],\n  "Ecuador": ["Ecuador"],\n  "Suecia": ["Sweden"],\n  "Túnez": ["Tunisia"],\n  "España": ["Spain"],\n  "Cabo Verde": ["Cape Verde", "Cabo Verde"],\n  "Bélgica": ["Belgium"],\n  "Egipto": ["Egypt"],\n  "Arabia Saudí": ["Saudi Arabia"],\n  "Uruguay": ["Uruguay"],\n  "Irán": ["Iran"],\n  "Nueva Zelanda": ["New Zealand"],\n  "Francia": ["France"],\n  "Senegal": ["Senegal"],\n  "Irak": ["Iraq"],\n  "Noruega": ["Norway"],\n  "Argentina": ["Argentina"],\n  "Argelia": ["Algeria"],\n  "Austria": ["Austria"],\n  "Jordania": ["Jordan"],\n  "Portugal": ["Portugal"],\n  "RD Congo": ["DR Congo", "Congo DR", "Congo Democratic Republic", "Democratic Republic of the Congo"],\n  "Inglaterra": ["England"],\n  "Croacia": ["Croatia"],\n  "Ghana": ["Ghana"],\n  "Panamá": ["Panama"],\n  "Uzbekistán": ["Uzbekistan"],\n  "Colombia": ["Colombia"]\n};\n\nfunction aliasesFor(team: string): string[] {\n  return [team, ...(TEAM_ALIASES[team] ?? [])].map(normalize);\n}\n\nfunction sameDate(apiDateTime: string, matchDate?: string): boolean {\n  if (!matchDate) return true;\n  return apiDateTime.slice(0, 10) === matchDate;\n}\n\nfunction fixtureStatus(short: string | null): MatchResult["status"] {\n  if (!short) return "SCHEDULED";\n\n  if (["FT", "AET", "PEN"].includes(short)) return "FINISHED";\n  if (["1H", "2H", "HT", "ET", "BT", "P", "LIVE"].includes(short)) return "LIVE";\n  return "SCHEDULED";\n}\n\nfunction matchFixture(match: Match, fixture: ApiFootballFixture): "direct" | "reverse" | null {\n  if (!sameDate(fixture.fixture.date, match.date)) return null;\n\n  const matchHomeAliases = aliasesFor(match.home);\n  const matchAwayAliases = aliasesFor(match.away);\n  const apiHome = normalize(fixture.teams.home.name);\n  const apiAway = normalize(fixture.teams.away.name);\n\n  if (matchHomeAliases.includes(apiHome) && matchAwayAliases.includes(apiAway)) {\n    return "direct";\n  }\n\n  if (matchHomeAliases.includes(apiAway) && matchAwayAliases.includes(apiHome)) {\n    return "reverse";\n  }\n\n  return null;\n}\n\nexport async function getApiFootballResults(): Promise<ApiResultsPayload> {\n  const apiKey = process.env.API_FOOTBALL_KEY;\n\n  if (!apiKey) {\n    return {\n      results: {},\n      updatedAt: new Date().toISOString(),\n      source: "api-football",\n      matchedFixtures: 0,\n      error: "Falta API_FOOTBALL_KEY en las variables de entorno."\n    };\n  }\n\n  const url = `${API_URL}?league=${WORLD_CUP_LEAGUE_ID}&season=${WORLD_CUP_SEASON}`;\n\n  try {\n    const response = await fetch(url, {\n      headers: {\n        "x-apisports-key": apiKey\n      },\n      next: {\n        revalidate: 60\n      }\n    });\n\n    if (!response.ok) {\n      return {\n        results: {},\n        updatedAt: new Date().toISOString(),\n        source: "api-football",\n        matchedFixtures: 0,\n        error: `API-Football respondió con HTTP ${response.status}.`\n      };\n    }\n\n    const data = (await response.json()) as ApiFootballResponse;\n    const fixtures = data.response ?? [];\n    const results: Record<string, MatchResult> = {};\n    let matchedFixtures = 0;\n\n    for (const match of matches) {\n      const found = fixtures\n        .map((fixture) => ({ fixture, direction: matchFixture(match, fixture) }))\n        .find((item) => item.direction !== null);\n\n      if (!found) continue;\n\n      matchedFixtures += 1;\n\n      const { fixture, direction } = found;\n      const homeGoals = direction === "direct" ? fixture.goals.home : fixture.goals.away;\n      const awayGoals = direction === "direct" ? fixture.goals.away : fixture.goals.home;\n\n      if (typeof homeGoals !== "number" || typeof awayGoals !== "number") {\n        continue;\n      }\n\n      results[match.id] = {\n        homeGoals,\n        awayGoals,\n        status: fixtureStatus(fixture.fixture.status.short),\n        minute: fixture.fixture.status.elapsed ?? undefined,\n        updatedAt: new Date().toISOString()\n      };\n    }\n\n    return {\n      results,\n      updatedAt: new Date().toISOString(),\n      source: "api-football",\n      matchedFixtures\n    };\n  } catch (error) {\n    return {\n      results: {},\n      updatedAt: new Date().toISOString(),\n      source: "api-football",\n      matchedFixtures: 0,\n      error: error instanceof Error ? error.message : "Error desconocido consultando API-Football."\n    };\n  }\n}\n',
    "lib/scoring.ts": 'import matches from "@/data/matches.json";\nimport predictions from "@/data/predictions.json";\nimport players from "@/data/players.json";\nimport type { Match, MatchResult, Pick, Prediction, ScoredPrediction, Standing } from "./types";\n\nconst allMatches = matches as Match[];\nconst allPredictions = predictions as Prediction[];\nconst allPlayers = players as string[];\n\nexport type PlayerSummary = {\n  player: string;\n  played: number;\n  correct: number;\n  wrong: number;\n  pending: number;\n};\n\nexport function signFromResult(result?: MatchResult): Pick | undefined {\n  if (!result) return undefined;\n  if (result.homeGoals > result.awayGoals) return "1";\n  if (result.homeGoals < result.awayGoals) return "2";\n  return "X";\n}\n\nexport function scorePrediction(prediction: Prediction, result?: MatchResult): number {\n  const actual = signFromResult(result);\n  if (!actual) return 0;\n  return prediction.pick === actual ? 1 : 0;\n}\n\nexport function getResults(): Record<string, MatchResult> {\n  return {};\n}\n\nexport function getMatches(): Match[] {\n  return allMatches;\n}\n\nexport function getPlayers(): string[] {\n  return allPlayers;\n}\n\nexport function getPredictions(): Prediction[] {\n  return allPredictions;\n}\n\nexport function getScoredPredictions(results: Record<string, MatchResult> = {}): ScoredPrediction[] {\n  const matchById = new Map(allMatches.map((match) => [match.id, match]));\n\n  return allPredictions.map((prediction) => {\n    const match = matchById.get(prediction.matchId);\n    if (!match) {\n      throw new Error(`Missing match ${prediction.matchId}`);\n    }\n\n    const result = results[prediction.matchId];\n    const actual = signFromResult(result);\n    const points = scorePrediction(prediction, result);\n\n    return {\n      ...prediction,\n      match,\n      result,\n      actual,\n      points,\n      isCorrect: actual ? prediction.pick === actual : null\n    };\n  });\n}\n\nexport function getStandings(results: Record<string, MatchResult> = {}): Standing[] {\n  const scored = getScoredPredictions(results);\n  const table = new Map<string, Standing>();\n\n  for (const player of allPlayers) {\n    table.set(player, {\n      player,\n      points: 0,\n      played: 0,\n      correct: 0,\n      pending: allMatches.length,\n      percentage: 0\n    });\n  }\n\n  for (const item of scored) {\n    const row = table.get(item.player);\n    if (!row) continue;\n\n    if (item.actual) {\n      row.played += 1;\n      row.pending -= 1;\n      row.points += item.points;\n      if (item.isCorrect) row.correct += 1;\n    }\n  }\n\n  return [...table.values()]\n    .map((row) => ({\n      ...row,\n      percentage: row.played > 0 ? Math.round((row.correct / row.played) * 100) : 0\n    }))\n    .sort((a, b) => {\n      if (b.points !== a.points) return b.points - a.points;\n      if (b.percentage !== a.percentage) return b.percentage - a.percentage;\n      return a.player.localeCompare(b.player, "es");\n    });\n}\n\nexport function getPlayerPredictions(\n  player: string,\n  results: Record<string, MatchResult> = {}\n): ScoredPrediction[] {\n  return getScoredPredictions(results)\n    .filter((item) => item.player.toLowerCase() === decodeURIComponent(player).toLowerCase())\n    .sort((a, b) => a.match.order - b.match.order);\n}\n\nexport function getMatchPredictions(\n  matchId: string,\n  results: Record<string, MatchResult> = {}\n): ScoredPrediction[] {\n  return getScoredPredictions(results)\n    .filter((item) => item.matchId === matchId)\n    .sort((a, b) => a.player.localeCompare(b.player, "es"));\n}\n\nexport function getPlayerSummary(\n  player: string,\n  results: Record<string, MatchResult> = {}\n): PlayerSummary {\n  const predictions = getPlayerPredictions(player, results);\n  const played = predictions.filter((item) => item.actual).length;\n  const correct = predictions.filter((item) => item.isCorrect === true).length;\n  const wrong = predictions.filter((item) => item.isCorrect === false).length;\n\n  return {\n    player,\n    played,\n    correct,\n    wrong,\n    pending: allMatches.length - played\n  };\n}\n\nexport function getPlayerSummaries(results: Record<string, MatchResult> = {}): PlayerSummary[] {\n  return allPlayers.map((player) => getPlayerSummary(player, results));\n}\n',
    "lib/types.ts": 'export type Pick = "1" | "X" | "2";\n\nexport type Match = {\n  id: string;\n  home: string;\n  away: string;\n  label: string;\n  order: number;\n  group?: string;\n  date?: string;\n  timeLocal?: string;\n  timeEt?: string;\n  city?: string;\n  stadium?: string;\n};\n\nexport type Prediction = {\n  matchId: string;\n  player: string;\n  pick: Pick;\n};\n\nexport type MatchResult = {\n  homeGoals: number;\n  awayGoals: number;\n  status?: "SCHEDULED" | "LIVE" | "FINISHED";\n  minute?: number;\n  updatedAt?: string;\n};\n\nexport type ScoredPrediction = Prediction & {\n  match: Match;\n  result?: MatchResult;\n  actual?: Pick;\n  points: number;\n  isCorrect: boolean | null;\n};\n\nexport type Standing = {\n  player: string;\n  points: number;\n  played: number;\n  correct: number;\n  pending: number;\n  percentage: number;\n};\n',
    "app/api/results/route.ts": 'import { NextResponse } from "next/server";\nimport { getApiFootballResults } from "@/lib/apiFootball";\n\nexport const dynamic = "force-dynamic";\n\nexport async function GET() {\n  const payload = await getApiFootballResults();\n  return NextResponse.json(payload);\n}\n',
    "app/page.tsx": 'import { StandingCard } from "@/components/StandingCard";\nimport { getApiFootballResults } from "@/lib/apiFootball";\nimport { getMatches, getStandings } from "@/lib/scoring";\n\nexport const dynamic = "force-dynamic";\n\nexport default async function HomePage() {\n  const payload = await getApiFootballResults();\n  const standings = getStandings(payload.results);\n  const played = Object.keys(payload.results).length;\n  const total = getMatches().length;\n\n  return (\n    <section>\n      <div className="hero">\n        <div className="kicker">Mundial 2026</div>\n        <h1>Porra primera fase</h1>\n        <p>\n          {played}/{total} partidos puntuados\n          {payload.error ? " · API pendiente" : ""}\n        </p>\n      </div>\n\n      <div className="section-title">\n        <h2>Clasificación</h2>\n        <span>1 punto por signo acertado</span>\n      </div>\n\n      <div className="stack">\n        {standings.map((row, index) => (\n          <StandingCard key={row.player} row={row} position={index + 1} />\n        ))}\n      </div>\n    </section>\n  );\n}\n',
    "app/partidos/page.tsx": 'import { MatchCard } from "@/components/MatchCard";\nimport { formatLongMatchDate } from "@/lib/format";\nimport { getApiFootballResults } from "@/lib/apiFootball";\nimport { getMatches } from "@/lib/scoring";\n\nexport const dynamic = "force-dynamic";\n\nexport default async function MatchesPage() {\n  const matches = getMatches();\n  const payload = await getApiFootballResults();\n\n  const grouped = matches.reduce((acc, match) => {\n    const key = match.date ?? "Fecha pendiente";\n    if (!acc[key]) acc[key] = [];\n    acc[key].push(match);\n    return acc;\n  }, {} as Record<string, typeof matches>);\n\n  return (\n    <section>\n      <div className="page-header">\n        <h1>Partidos</h1>\n        <p>\n          Fecha, grupo, horario local, horario español y pronósticos de la porra.\n          {payload.error ? " La API todavía no está devolviendo resultados." : ""}\n        </p>\n      </div>\n\n      <div className="date-stack">\n        {Object.entries(grouped).map(([date, dayMatches]) => (\n          <section key={date} className="date-section">\n            <h2>{formatLongMatchDate(date)}</h2>\n            <div className="stack">\n              {dayMatches.map((match) => (\n                <MatchCard key={match.id} match={match} result={payload.results[match.id]} />\n              ))}\n            </div>\n          </section>\n        ))}\n      </div>\n    </section>\n  );\n}\n',
    "app/pronosticos/page.tsx": 'import Link from "next/link";\nimport { normalizePlayerForUrl } from "@/lib/format";\nimport { getApiFootballResults } from "@/lib/apiFootball";\nimport { getPlayerSummaries } from "@/lib/scoring";\n\nexport const dynamic = "force-dynamic";\n\nexport default async function PredictionsPage() {\n  const payload = await getApiFootballResults();\n  const players = getPlayerSummaries(payload.results);\n\n  return (\n    <section>\n      <div className="page-header">\n        <h1>Pronósticos</h1>\n        <p>La quiniela individual de cada jugador.</p>\n      </div>\n\n      <div className="grid-list">\n        {players.map((row) => (\n          <Link key={row.player} href={`/pronosticos/${normalizePlayerForUrl(row.player)}`} className="player-tile">\n            <span>{row.player}</span>\n            <div className="pronostic-summary">\n              {row.played === 0 ? (\n                <>Ver quiniela</>\n              ) : (\n                <>{row.correct} aciertos · {row.wrong} fallos</>\n              )}\n            </div>\n          </Link>\n        ))}\n      </div>\n    </section>\n  );\n}\n',
    "app/pronosticos/[player]/page.tsx": 'import Link from "next/link";\nimport { notFound } from "next/navigation";\nimport { formatMatchDate, resultLabel } from "@/lib/format";\nimport { getApiFootballResults } from "@/lib/apiFootball";\nimport { getPlayerPredictions, getPlayerSummary, getPlayers } from "@/lib/scoring";\n\nexport const dynamic = "force-dynamic";\n\nexport function generateStaticParams() {\n  return getPlayers().map((player) => ({ player }));\n}\n\nexport default async function PlayerPredictionPage({\n  params,\n}: {\n  params: Promise<{ player: string }>;\n}) {\n  const { player: rawPlayer } = await params;\n  const player = decodeURIComponent(rawPlayer);\n\n  const payload = await getApiFootballResults();\n  const predictions = getPlayerPredictions(player, payload.results);\n  if (predictions.length === 0) notFound();\n\n  const summary = getPlayerSummary(player, payload.results);\n\n  return (\n    <section>\n      <div className="page-header">\n        <Link href="/pronosticos" className="back">← Pronósticos</Link>\n        <h1>{player}</h1>\n        <p>\n          {summary.played === 0\n            ? "Quiniela completa"\n            : `${summary.correct} aciertos · ${summary.wrong} fallos · ${summary.pending} pendientes`}\n        </p>\n      </div>\n\n      <div className="stack">\n        {predictions.map((item) => (\n          <article key={item.matchId} className="prediction-card">\n            <div>\n              <div className="meta-row">\n                <span>{formatMatchDate(item.match.date)}</span>\n                <span className="group-chip">Grupo {item.match.group ?? "—"}</span>\n              </div>\n              <div className="match-label">{item.match.label}</div>\n              <div className="muted">Resultado: {resultLabel(payload.results[item.matchId])}</div>\n            </div>\n            <div className="prediction-right">\n              <span className="chip">{item.pick}</span>\n              {item.isCorrect === null ? (\n                <span className="pill pending">Pendiente</span>\n              ) : item.isCorrect ? (\n                <span className="pill ok">+1</span>\n              ) : (\n                <span className="pill ko">0</span>\n              )}\n            </div>\n          </article>\n        ))}\n      </div>\n    </section>\n  );\n}\n',
    "app/admin/page.tsx": 'import { getApiFootballResults } from "@/lib/apiFootball";\n\nexport const dynamic = "force-dynamic";\n\nexport default async function AdminPage() {\n  const payload = await getApiFootballResults();\n\n  return (\n    <section>\n      <div className="page-header">\n        <h1>Estado API</h1>\n        <p>Pantalla oculta para comprobar si API-Football está respondiendo.</p>\n      </div>\n\n      <div className="code-card">\n        <p>Fuente: {payload.source}</p>\n        <p>Partidos emparejados: {payload.matchedFixtures}</p>\n        <p>Resultados con marcador: {Object.keys(payload.results).length}</p>\n        <p>Última actualización: {payload.updatedAt}</p>\n        {payload.error ? <p>Error: {payload.error}</p> : null}\n      </div>\n\n      <div className="code-card">\n        <p>Respuesta resumida:</p>\n        <pre>{JSON.stringify(payload, null, 2)}</pre>\n      </div>\n    </section>\n  );\n}\n',
}

for rel, content in files.items():
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")

gitignore = ROOT / ".gitignore"
existing = gitignore.read_text(encoding="utf-8") if gitignore.exists() else ""
if ".env.local" not in existing:
    gitignore.write_text(existing.rstrip() + "\n\n" + '# Local API keys\n.env.local\n.env\n' + "\n", encoding="utf-8")

print("Versión 3 aplicada: resultados desde API-Football, sin Supabase y sin resultados manuales.")
print("Ahora crea .env.local con API_FOOTBALL_KEY y ejecuta npm run build.")
